+export function warnIfImbalanced(loads: number[], threshold: number, warn: (message: string) => void): void {
+  if (!threshold || !loads.length) {
+    return
+  }
+  const max = Math.max(...loads)
+  const ratio = max === 0 ? 1 : Math.min(...loads) / max
+  if (ratio < threshold) {
+    warn(`Shard duration imbalance: ratio=${ratio.toFixed(2)} threshold=${threshold.toFixed(2)}`)
+  }
