+export type DurationHistory = Record<string, DurationObservation[]>
+
+function observations(value: unknown): DurationObservation[] | null {
+  const values = typeof value === 'number'
+    ? [{ duration: value, recordedAt: 0 }]
+    : value && typeof value === 'object' && 'observations' in value
+      ? (value as { observations: unknown }).observations
+      : value && typeof value === 'object' && 'duration' in value
+        ? [value]
+        : null
+  if (!Array.isArray(values) || values.some(value => !value || typeof value !== 'object' || !Number.isFinite((value as DurationObservation).duration) || !Number.isFinite((value as DurationObservation).recordedAt))) {
+    return null
+  }
+  return values as DurationObservation[]
+}
+
+export async function readDurationHistory(root: string, path: string, ttl: number): Promise<DurationHistory | null> {
+  try {
+    const raw = JSON.parse(await fs.readFile(resolve(root, path), 'utf8'))
+    if (!raw || typeof raw !== 'object' || Array.isArray(raw)) {
+      return null
+    }
+    const expiresAt = ttl > 0 ? Date.now() - ttl : -Infinity
+    const history: DurationHistory = {}
+    for (const [file, value] of Object.entries(raw)) {
+      const entries = observations(value)
+      if (!entries) {
+        return null
+      }
+      history[file] = entries.filter(entry => entry.recordedAt === 0 || entry.recordedAt >= expiresAt)
+    }
+    return history
+  }
+  catch {
+    return null
+  }
+}
